require "ui.window.GUIIllustrationItem"
require "config.ItemConfig"

GUIIllustrationList = class("GUIIllustrationList", IGUIWindow)

function GUIIllustrationList:onLoad()
    self.tabId = 0
end

function GUIIllustrationList:initList(tabId)
    self.tabId = tabId
    self.itemsList = IGUIGridView.new("lucky_sky_hall_illustration_list" .. tabId, self:getChildWindow(0, GUIType.Layout))
    local contentWidth = self.itemsList:getWidth()
    local itemWidth = contentWidth * 0.15
    self.itemsList:setConfig(contentWidth * 0.0196, contentWidth * 0.0196, 6)

    local items = ItemConfig:getItemsByTab(self.tabId)
    for _, item in pairs(items) do
        local llItem = GUIIllustrationItem.new("LuckySkyHallIllustratedItem.json")
        llItem:setWidth({ 0, itemWidth })
        llItem:setHeight({ 0, itemWidth })
        self.itemsList:addItem(llItem)
        llItem:initItem(item)
    end
end

return GUIIllustrationList